pub const MODEL_ID: &str = "lv2_pitchotto";
pub const DISPLAY_NAME: &str = "Pitchotto";
const BRAND: &str = "shiro";

const PLUGIN_URI: &str = "https://github.com/ninodewit/SHIRO-Plugins/plugins/pitchotto";
const PLUGIN_DIR: &str = "Pitchotto";

#[cfg(target_os = "macos")]
const PLUGIN_BINARY: &str = "Pitchotto_dsp.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "Pitchotto_dsp.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "Pitchotto_dsp.dll";

// Port indices (from TTL)
const PORT_AUDIO_IN_LV2_AUDIO_IN_1: usize = 0;
const PORT_AUDIO_OUT_LV2_AUDIO_OUT_1: usize = 1;
const PORT_CTRL_RATIO2: usize = 2;
const PORT_CTRL_MIX: usize = 3;
const PORT_CTRL_DELAY1: usize = 4;
const PORT_CTRL_RATIO1: usize = 5;
const PORT_CTRL_CUTOFF: usize = 6;
const PORT_CTRL_BLUR: usize = 7;
const PORT_CTRL_DELAY2: usize = 8;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_PITCH.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::DualMono,
        parameters: vec![
            float_parameter("ratio2", "ratio2", None, Some(2.0), 0.5, 2.0, 0.01, ParameterUnit::None),
            float_parameter("mix", "mix", None, Some(0.5), 0.0, 1.0, 0.01, ParameterUnit::None),
            float_parameter("delay1", "delay1", None, Some(100.0), 0.1, 1000.0, 1.0, ParameterUnit::None),
            float_parameter("ratio1", "ratio1", None, Some(0.5), 0.5, 2.0, 0.01, ParameterUnit::None),
            float_parameter("cutoff", "cutoff", None, Some(2250.0), 0.0, 3000.0, 10.0, ParameterUnit::None),
            float_parameter("blur", "blur", None, Some(0.25), 0.01, 0.25, 0.001, ParameterUnit::None),
            float_parameter("delay2", "delay2", None, Some(100.0), 0.1, 1000.0, 1.0, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let ratio2 = required_f32(params, "ratio2").map_err(anyhow::Error::msg)?;
    let mix = required_f32(params, "mix").map_err(anyhow::Error::msg)?;
    let delay1 = required_f32(params, "delay1").map_err(anyhow::Error::msg)?;
    let ratio1 = required_f32(params, "ratio1").map_err(anyhow::Error::msg)?;
    let cutoff = required_f32(params, "cutoff").map_err(anyhow::Error::msg)?;
    let blur = required_f32(params, "blur").map_err(anyhow::Error::msg)?;
    let delay2 = required_f32(params, "delay2").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_RATIO2, ratio2),
        (PORT_CTRL_MIX, mix),
        (PORT_CTRL_DELAY1, delay1),
        (PORT_CTRL_RATIO1, ratio1),
        (PORT_CTRL_CUTOFF, cutoff),
        (PORT_CTRL_BLUR, blur),
        (PORT_CTRL_DELAY2, delay2),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_LV2_AUDIO_IN_1], &[PORT_AUDIO_OUT_LV2_AUDIO_OUT_1], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_LV2_AUDIO_IN_1], &[PORT_AUDIO_OUT_LV2_AUDIO_OUT_1], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_LV2_AUDIO_IN_1], &[PORT_AUDIO_OUT_LV2_AUDIO_OUT_1], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

pub const MODEL_DEFINITION: PitchModelDefinition = PitchModelDefinition {
    id: MODEL_ID, display_name: DISPLAY_NAME, brand: BRAND,
    backend_kind: PitchBackendKind::Lv2, schema, build,
    supported_instruments: block_core::ALL_INSTRUMENTS, knob_layout: &[],
};
